#include <iostream>
#include <vector>

using namespace std;

int main()
{
    vector<int> numbers = {10, 20, 30};

    for (int n : numbers)
    {
        cout << n << " ";
    }

    return 0;
}

// for (int n : numbers) { ... } is roughly equivalent to:

for (auto it = numbers.begin(); it != numbers.end(); it++)
{
    int n = *it;
    // ...
}

vector<int> numbers = {1, 2, 3};

for (int n : numbers)
{
    n = n * 10; // only changes the LOCAL COPY n — numbers is untouched
}
// numbers is still {1, 2, 3}

for (int &n : numbers)
{
    n = n * 10; // n is a REFERENCE to the real element — this DOES change numbers
}
// numbers is now {10, 20, 30}

for (const int &n : numbers)
{
    cout << n; // read freely, but n = 5; here would be a compile error
}

map<string, int> ages = {{"Aman", 20}, {"Priya", 22}};

for (const auto &entry : ages) // recall: iterating a map gives pair elements
{
    cout << entry.first << ": " << entry.second << endl;
}

